#!/usr/bin/env bash
# verify-wave6.sh — terminal proof for the Wave 6 supply-chain pillar.
#
# Runs the full Wave 6 happy-path end-to-end in an isolated venv:
#   1.  Creates a clean venv at ${TMPDIR:-/tmp}/wave6-venv (python3 -m venv).
#   2.  Activates it.
#   3.  pip install --require-hashes -r requirements.txt
#       (the hash-pinned, platform-universal lockfile generated by
#       `uv pip compile --universal --generate-hashes` from requirements.in —
#       any unhashed/mismatched entry fails-closed. Per-OS markers mean this
#       Linux run installs only the Linux wheels, skipping the win32 ones).
#   4.  python -c 'import jarvis'   (smoke that the package is importable
#       after the hash-pinned install).
#   5.  pip install pip-audit       (the audit tool itself does NOT need
#       a hash pin — it's analysis-only, not runtime code).
#   6.  pip-audit -r requirements.txt --strict
#       (--strict upgrades osv.dev/PyPI advisory-lookup failures to
#       exit-non-zero alongside any CVE match — no silent passes).
#
# On all six steps OK: prints exactly `WAVE6_OK` on its own line, exit 0.
# Any failure: prints what failed and exits non-zero.
#
# Designed to run in a Docker python:3.11-slim container with zero
# additional apt packages. pip-audit's transitive deps (cryptography,
# cffi) on slim need build-essential + libssl-dev because some wheels
# are not on the slim image — handle in-script. NEVER relax --strict
# or --require-hashes.
#
# See docs/supply-chain/threat-model.md §11 for the threat model.

set -euo pipefail

REPO_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
VENV_DIR="${TMPDIR:-/tmp}/wave6-venv"

cleanup() {
    # Don't blow away the venv on success — useful for offline debugging.
    # On failure we leave it so the user can `source bin/activate` and
    # poke at what went wrong.
    :
}
trap cleanup EXIT

# -----------------------------------------------------------------------
# Step 0: defensive bootstrap for slim Docker images
# -----------------------------------------------------------------------
# pip-audit's transitive deps (cryptography, cffi) often need a C
# compiler + libssl-dev + libffi-dev on python:3.11-slim because not
# every linux/amd64 wheel is published. If apt is available AND we're
# missing gcc, install the build deps quietly. Outside Docker (where
# the user has a real toolchain) this is a no-op.
ensure_build_deps() {
    if command -v apt-get >/dev/null 2>&1 && ! command -v gcc >/dev/null 2>&1; then
        echo "verify-wave6: bootstrapping build deps (apt-get) for pip-audit transitive wheels..."
        if [ "$(id -u)" -eq 0 ]; then
            apt-get update >/dev/null
            apt-get install -y --no-install-recommends \
                build-essential \
                libssl-dev \
                libffi-dev \
                pkg-config \
                >/dev/null
        else
            echo "verify-wave6: not root, skipping apt-get; assuming gcc/libssl-dev already present"
        fi
    fi
}
ensure_build_deps

# -----------------------------------------------------------------------
# Step 1: clean venv
# -----------------------------------------------------------------------
if [ -d "$VENV_DIR" ]; then
    echo "verify-wave6: removing stale venv at $VENV_DIR"
    rm -rf "$VENV_DIR"
fi

if ! python3 -m venv "$VENV_DIR"; then
    echo "verify-wave6: FAIL — python3 -m venv $VENV_DIR did not succeed"
    exit 1
fi

# -----------------------------------------------------------------------
# Step 2: activate
# -----------------------------------------------------------------------
# shellcheck disable=SC1091
. "$VENV_DIR/bin/activate"

# Upgrade pip so --require-hashes plays nicely with the lockfile shape
# the compiler emits. Older pip (<22) had bugs with hash-checking on
# binary-only wheels.
python -m pip install --upgrade pip >/dev/null

# -----------------------------------------------------------------------
# Step 3: hash-pinned install
# -----------------------------------------------------------------------
echo "verify-wave6: pip install --require-hashes -r $REPO_ROOT/requirements.txt"
if ! python -m pip install --require-hashes -r "$REPO_ROOT/requirements.txt"; then
    echo "verify-wave6: FAIL — hash-pinned install rejected by pip"
    echo "verify-wave6: this means either (a) requirements.txt has an unhashed"
    echo "verify-wave6: entry, (b) a published wheel diverges from the pinned hash,"
    echo "verify-wave6: or (c) PyPI is unreachable from this host."
    exit 1
fi

# -----------------------------------------------------------------------
# Step 4: importable smoke (requires the editable install of jarvis itself
# so `import jarvis` resolves to the source tree under $REPO_ROOT)
# -----------------------------------------------------------------------
# `requirements.txt` carries the deps, NOT the project itself. Install
# the project with --no-deps so the hash-pinned dep set is not disturbed
# (otherwise pip would re-resolve transitive deps from pyproject.toml).
echo "verify-wave6: pip install -e . --no-deps"
if ! python -m pip install -e "$REPO_ROOT" --no-deps >/dev/null; then
    echo "verify-wave6: FAIL — editable install of personal-jarvis failed"
    exit 1
fi

echo "verify-wave6: python -c 'import jarvis'"
if ! python -c "import jarvis"; then
    echo "verify-wave6: FAIL — 'import jarvis' raised after hash-pinned install"
    exit 1
fi

# -----------------------------------------------------------------------
# Step 5: pip-audit install
# -----------------------------------------------------------------------
echo "verify-wave6: pip install pip-audit"
if ! python -m pip install "pip-audit==2.10.0" >/dev/null; then
    echo "verify-wave6: FAIL — pip-audit install failed"
    exit 1
fi

# -----------------------------------------------------------------------
# Step 6: pip-audit --strict
# -----------------------------------------------------------------------
echo "verify-wave6: pip-audit -r requirements.txt --strict"
if ! python -m pip_audit -r "$REPO_ROOT/requirements.txt" --strict --progress-spinner=off --disable-pip; then
    echo "verify-wave6: FAIL — pip-audit reported a vulnerability or an advisory-lookup failure under --strict"
    exit 1
fi

# All six steps green. Emit the goal-terminal proof token.
echo "WAVE6_OK"
exit 0
